import boto3
import json
import pymysql
from pymysql import err

rds_instance = 'your-rds-instance'
rds_username = 'your-rds-username'
rds_password = 'your-rds-password'

def lambda_handler(event, context):
    try:
        conn = pymysql.connect(
            host=rds_instance,
            user=rds_username,
            password=rds_password,
            database='your-database-name',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        with conn.cursor() as cur:
            query = "SELECT * FROM products WHERE 1=1"
            
            if 'name' in event['queryStringParameters']:
                query += " AND name LIKE %s"
                params = (f"%{event['queryStringParameters']['name']}%")
                
            if 'category' in event['queryStringParameters']:
                query += " AND category = %s"
                params = (event['queryStringParameters']['category'],) + params
                
            if 'price' in event['queryStringParameters']:
                query += " AND price BETWEEN %s AND %s"
                params = (float(event['queryStringParameters']['price']), float(event['queryStringParameters']['price'])) + params
                
            cur.execute(query, params)
            
            products = cur.fetchall()
            
        conn.close()
        
        return {
            'statusCode': 200,
            'body': json.dumps(products)
        }
    
    except err.Error as e:
        print(e)
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }

    except Exception as e:
        print(e)
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }